    ('Eisbär Eis', 'Nussa Nougat Creme', 'https://images.openfoodfacts.org/images/products/433/561/921/5894/front_de.18.400.jpg', 'off_api', 'front', true, 'Front — EAN 4335619215894', 'front_4335619215894'),
    ('Bruno Gelato', 'ACE Eis', 'https://images.openfoodfacts.org/images/products/426/005/982/4972/front_de.8.400.jpg', 'off_api', 'front', true, 'Front — EAN 4260059824972', 'front_4260059824972'),
