    ('Harvest Basket', 'Jumbo Fries Pommes offen', 'https://images.openfoodfacts.org/images/products/000/002/024/9243/front_de.3.400.jpg', 'off_api', 'front', true, 'Front — EAN 20249243', 'front_20249243'),
